)
public class CucumberTest {
}

package org.apache.commons.math.geometry.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.geometry.Vector3D;
import org.apache.commons.math.exception.MathArithmeticException;

import static org.junit.Assert.assertEquals;

import java.util.Map;
import java.util.HashMap;

public class StepDefs {
    private Vector3D v1, v2, result;

    @Given("two vectors v1 and v2 with large coordinates:")
    public void given_two_vectors_v1_and_v2_with_large_coordinates(io.cucumber.datatable.DataTable dataTable) {
        Map<String, Double> coordsMap = new HashMap<>();

        // Skip the header and process each row
        for (Map<String, String> row : dataTable.asMaps()) {
            String vector = row.get("vector");
            double x = Double.parseDouble(row.get("x"));
            double y = Double.parseDouble(row.get("y"));
            double z = Double.parseDouble(row.get("z"));

            Vector3D vector3d = new Vector3D(x, y, z);

            if ("v1".equals(vector)) {
                v1 = vector3d;
            } else if ("v2".equals(vector)) {
                v2 = vector3d;
            }
        }
    }

    @When("I compute the cross product of v1 and v2")
    public void when_i_compute_the_cross_product_of_v1_and_v2() {
        try {
            result = v1.crossProduct(v2);
        } catch (MathArithmeticException e) {
            // Handle potential arithmetic exceptions if they occur
            result = new Vector3D(Double.NaN, Double.NaN, Double.NaN);
        }
    }

    @Then("the result x coordinate should be {double}")
    public void then_the_result_x_coordinate_should_be(double expectedX) {
        assertEquals("Cross product x coordinate is incorrect", expectedX, result.getX(), 1e-10);
    }

    @Then("the result y coordinate should be {double}")
    public void then_the_result_y_coordinate_should_be(double expectedY) {
        assertEquals("Cross product y coordinate is incorrect", expectedY, result.getY(), 1e-10);
    }

    @Then("the result z coordinate should be {double}")
    public void then_the_result_z_coordinate_should_be(double expectedZ) {
        assertEquals("Cross product z coordinate is incorrect", expectedZ, result.getZ(), 1e-10);
    }
}

